//==== CREATE CANVAS ====
function createCanvas(data){
  let canvas=document.createElement('div')
  canvas.id=_ez.canvas
  canvas.style.height='100%'
  document.body.appendChild(canvas)
  localStorage.setItem('serviceWorker',data.name)
  uid=localStorage.getItem('_UID')
  uid=uid?uid:userUID()
  if(lsRd('eFirstRun')==null){
    setTimeout(function(){
      location.href='engine/engine.html#world='+data.level+'?'+uid
    },1200)
  }else if(navigator.onLine){
    document.getElementById(_ez.canvas).innerHTML='<object type="text/html" data="engine/engine.html#world='+data.level+'?'+uid+'" id="'+_ez.canvas+'-frame" style="width:100%;height:100vh"></object>'
    window.onmessage=function(e){
      console.log(e.data.operation,e.data.message)
    }
    setTimeout(()=>{
      document.getElementById(_ez.canvas+'-frame').contentWindow.postMessage({operation:'load-asset',message:'Connected.'})
    },10000)
  }else location.href='engine/engine.html#world='+data.level+'?'+uid
}
//========= SOCIAL =========
//Social
function appSocial(nm,ds,im,url,kw){
  metaTag(null,'og:title',nm);
  metaTag(null,'og:description',ds);
  metaTag(null,'og:image',im);
  metaTag(null,'og:url',url);
  metaTag('twitter:title',null,nm);
  metaTag('twitter:description',null,ds);
  metaTag('twitter:image',null,im);
  metaTag('twitter:url',null,url);
  metaTag('description',null,nm);
  metaTag('application-name',null,ds)
  metaTag('keywords',null,kw)
}
//Meta tag
function metaTag(name,prop,cont){
  meta=document.createElement('meta');
  if(name!=null)meta.name=name;
  if(prop!=null)meta.property=prop;
  if(cont!=null)meta.content=cont;
  document.getElementsByTagName('head')[0].appendChild(meta)
}
// ==== JAVASCRIPT & STYLE ====
// Uload script
function uloadScript(nm){
  te=document.getElementsByTagName('script')
  for(y=te.length;y>=0;y--){
    if(te[y]&&te[y].getAttribute('src')!=null&&te[y].getAttribute('src').indexOf(nm)!=-1)te[y].parentNode.removeChild(te[y])
  }
}
// Uload style
function uloadStyle(nm){
  te=document.getElementsByTagName('link:none')
  for(y=te.length;y>=0;y--){
    if(te[y]&&te[y].getAttribute('href:none')!=null&&te[y].getAttribute('href:none').indexOf(nm)!=-1)te[y].parentNode.removeChild(te[y])
  }
}
// Load script
function loadScript(jn,tg,typ){
  js=document.createElement('script')
  if(typ===undefined)typ='text/javascript'
  js.setAttribute('type',typ)
  js.setAttribute('src',jn)
  if(typeof js!="undefined")document.getElementsByTagName(tg)[0].appendChild(js)
}
// Load style
function loadStyle(cn,tg){
  var cs=document.createElement('link')
  cs.setAttribute('rel','stylesheet')
  cs.setAttribute('type','text/css')
  cs.setAttribute('href',cn)
  if(typeof cs!='undefined')document.getElementsByTagName(tg)[0].appendChild(cs)
}
// ==== WORKER ====
function createWorker(name){
  worker[name]={}
  worker[name].name=name
  setTimeout(function(){document.getElementById(worker[name].name).remove()},1200)
  worker[name].operation=new Worker(window.URL.createObjectURL(new Blob([
    document.querySelector('#'+worker[name].name).textContent
      .toString().replace(/^function .+\{?|\}$/g, '')
      .replace(/..\/..\//g,location.href.substring(0,location.href.lastIndexOf('/'))+'/assets/js/')
  ],{type:'text/javascript'})),{type:'module'})
}
// ==== GET URL ====
function isURL(allLevels){
  url=urlCodChr(location.href.split('#').slice(-1).toString())
  function assignLevels(i){
    _lz=allLevels[i]
    _lz.avatars=allAvatars(allLevels[i].index)
    allLevels[i].parameters=[].concat(isOnL()?randomString(_lz.avatars):_lz.avatars[0],allLevels[i].parameters)
  }
  if(url.includes('world=')){
    if(url.includes('?')){
      myUserID.uid=url.split('?').slice(-1).toString()
      myUserID.account=uidSN(myUserID.uid,4,5)
      lsSv('myUserID',JSON.stringify(myUserID))
      url=url.split('?')[0]
    }
    for(i=0;i<allLevels.length;i++){
      if(allLevels[i].levelName==url.replace('world=','')){
        assignLevels(i)
        continue
      }
    }
  }else if(allLevels[0].levelName=='external'+lsRd('levelname')){
    assignLevels(0)
  }else _lz=JSON.parse(url.replace('load=',''))
  return !JSON.stringify(_lz).match(/(engine\/engine)/)||allLevels[0].levelName=='external'+lsRd('levelname')
}
//Convert URL %Codes to char
function urlCodChr(url){
  return url.toString().replace(/%2C/g,',').replace(/%CF%85/g,'υ').replace(/%CF%82/g,'ς').replace(/%20/g,' ').replace(/%26/g,'&').replace(/%27/g,"\'").replace(/%22/g,'\"').replace(/%3C/g,'\<').replace(/%3E/g,'\>').replace(/%28/g,'(').replace(/%29/g,')').replace(/%5B/g,'[').replace(/%5D/g,']').replace(/%7B/g,'{').replace(/%7D/g,'}')
}
// ==== LOCAL STORAGE ====
// Save to local storage
function lsSv(lKey,lObj){localStorage.setItem(lKey,lObj)}
function lsRd(lKey){return localStorage.getItem(lKey)}
function lsEr(lKey){localStorage.removeItem(lKey)}
// ==== DETECT DEVICE ====
// Get orientation
function getOrientation(){
  isMobile=/Tablet|iPhone|iPad|iPod|Android/i.test(navigator.userAgent)
  orientation=window.innerWidth>window.innerHeight
}
// Full screen
function fullscreen(c0){
	if(c0){
		if(document.getElementById('engine-container').requestFullscreen){
	    document.getElementById('engine-container').requestFullscreen()
	  }else if(document.getElementById('engine-container').msRequestFullscreen){
	    document.getElementById('engine-container').msRequestFullscreen()
	  }else if(document.getElementById('engine-container').mozRequestFullScreen){
	    document.getElementById('engine-container').mozRequestFullScreen()
	  }else if(document.getElementById('engine-container').webkitRequestFullscreen){
	    document.getElementById('engine-container').webkitRequestFullscreen()
	  }
	}else{
		if(document.exitFullscreen){
			document.exitFullscreen()
		}else if(document.msExitFullscreen){
			document.msExitFullscreen()
		}else if(document.mozCancelFullScreen){
			document.mozCancelFullScreen()
		}else if(document.webkitExitFullscreen){
			document.webkitExitFullscreen()
		}
	}
}
// Detect if connected
function isOnL(){
  if(fbLdF){
    if(meAndF){
      return AppInterface.isAppOnline()
    }else if(navigator.onLine){
      return true
    }else return false
  }
}
